valueString.value:
/*
@input: Client's age is less than 5 months
@pseudocode: Today's date − "Date of birth" < 5 months
@code: Client's age is less than 5 months-41
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "Client's age is less than 5 months":
  Encounter."Current Patient Age In Months" < 5

/*
@output: Client is not due for malaria vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for malaria vaccination Case 1":
  Encounter."Client's age is less than 5 months"

/*
@internal: Malaria containing Doses Administered to Patient that are in the Primary series
*/
define "Malaria Primary Series Doses Administered to Patient":
  "Malaria Doses Administered to Patient".seriesPrimary()

/*
@internal: Number of Malaria Primary Series doses
*/
define "Number of Malaria Primary Series Doses Administered":
  Count("Malaria Primary Series Doses Administered to Patient")

/*
@input: One malaria primary series dose was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Malaria vaccines" and "Type of dose" = "Primary series") = 1
@code: One malaria primary series dose was administered-116
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "One malaria primary series dose was administered":
  "Number of Malaria Primary Series Doses Administered" = 1

/*
@internal: Date of Latest Malaria Dose
*/
define "Date of Latest Malaria Dose":
  date from start of "Malaria Doses Administered to Patient".mostRecent().occurrence.toInterval()

/*
@input: The latest malaria dose was administered less than 4 weeks ago
@pseudocode: Today's date − "Date and time of vaccination" (where "Vaccine type" = "Malaria vaccines") < 4 weeks
@code: The latest malaria dose was administered less than 4 weeks ago-99
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "The latest malaria dose was administered less than 4 weeks ago":
	"Date of Latest Malaria Dose" is not null
    and duration in weeks between "Date of Latest Malaria Dose" and Today < 4

/*
@output: Client is not due for malaria vaccination Case 2
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for malaria vaccination Case 2":
  Encounter."One malaria primary series dose was administered"
    and Encounter."The latest malaria dose was administered less than 4 weeks ago"

/*
@input: Two malaria primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Malaria vaccines" and "Type of dose" = "Primary series") = 2
@code: Two malaria primary series doses were administered-116
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "Two malaria primary series doses were administered":
  "Number of Malaria Primary Series Doses Administered" = 2

/*
@output: Client is not due for malaria vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for malaria vaccination Case 3":
  Encounter."Two malaria primary series doses were administered"
    and Encounter."The latest malaria dose was administered less than 4 weeks ago"

/*
@input: Three malaria primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Malaria vaccines" and "Type of dose" = "Primary series") = 3
@code: Three malaria primary series doses were administered-116
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "Three malaria primary series doses were administered":
  "Number of Malaria Primary Series Doses Administered" = 3

/*
@output: Client is not due for malaria vaccination Case 4
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for malaria vaccination Case 4":
  Encounter."Three malaria primary series doses were administered"
    and Encounter."The latest malaria dose was administered less than 4 weeks ago"

/*
@output: Client is not due for malaria vaccination
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for malaria vaccination":
  "Client is not due for malaria vaccination Case 1"
    or "Client is not due for malaria vaccination Case 2"
    or "Client is not due for malaria vaccination Case 3"
    or "Client is not due for malaria vaccination Case 4"

/*
@input: No malaria primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Malaria vaccines" and "Type of dose" = "Primary series") = 0
@code: No malaria primary series doses were administered-116
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "No malaria primary series doses were administered":
  "Number of Malaria Primary Series Doses Administered" = 0

/*
@input: Client's age is more than or equal to 5 months
@pseudocode: Today's date − "Date of birth" ≥ 5 months
@code: Client's age is more than or equal to 5 months-41
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "Client's age is more than or equal to 5 months":
  Encounter."Current Patient Age In Months" >= 5

/*
@output: Client is due for malaria vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for malaria vaccination Case 1":
  Encounter."No malaria primary series doses were administered"
    and Encounter."Client's age is more than or equal to 5 months"

/*
@input: The latest malaria dose was administered more than 4 weeks ago
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Vaccine type" = "Malaria vaccines") ≥ 4 weeks
@code: The latest malaria dose was administered more than 4 weeks ago-106
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "The latest malaria dose was administered more than 4 weeks ago":
  not "The latest malaria dose was administered less than 4 weeks ago"

/*
@output: Client is due for malaria vaccination Case 2
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for malaria vaccination Case 2":
  Encounter."One malaria primary series dose was administered"
    and Encounter."The latest malaria dose was administered more than 4 weeks ago"

/*
@output: Client is due for malaria vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for malaria vaccination Case 3":
  Encounter."Two malaria primary series doses were administered"
    and Encounter."The latest malaria dose was administered more than 4 weeks ago"

/*
@output: Client is due for malaria vaccination Case 4
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for malaria vaccination Case 4":
  Encounter."Three malaria primary series doses were administered"
    and Encounter."The latest malaria dose was administered more than 4 weeks ago"

/*
@output: Client is due for malaria vaccination
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for malaria vaccination":
  "Client is due for malaria vaccination Case 1"
    or "Client is due for malaria vaccination Case 2"
    or "Client is due for malaria vaccination Case 3"
    or "Client is due for malaria vaccination Case 4"

/*
@input: Four malaria primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Malaria vaccines" and "Type of dose" = "Primary series") = 4
@code: Four malaria primary series doses were administered-116
@decision: IMMZ.D2.DT.Malaria: 4-dose schedule (The RTS,S/AS01 malaria vaccine should be used for the prevention of Plasmodium falciparum malaria in children living in regions with moderate to high malaria transmission, as defined by WHO)
*/
define "Four malaria primary series doses were administered":
  "Number of Malaria Primary Series Doses Administered" = 4

/*
@output: Malaria immunization schedule is complete
@pseudocode: "Immunization recommendation status" = "Complete"
"Completed the primary vaccination series" = TRUE (where "Vaccine type" = "Malaria vaccines")"
*/
define "Malaria immunization schedule is complete":
  Encounter."Four malaria primary series doses were administered"

/*
@output: Malaria immunization schedule is complete Guidance
@guidance: Malaria immunization schedule is complete. Four malaria primary series doses were administered. 
Check for any other vaccines due.
*/
define "Malaria immunization schedule is complete Guidance":
  'Malaria immunization schedule is complete. Four malaria primary series doses were administered. 
Check for any other vaccines due.'
